from typing import Dict, Any, Callable


class Option:
    """The option class is the way Stages have to inform the Pipeline about
    the options it has.
    """

    def __init__(
        self,
        name: str,
        description: str,
        type_cast: Callable[[Any], Any],
        required: bool = True,
    ) -> None:
        """Option's initializer

        :param name: The name of the option
        :param description: Description of what it does
        :param type_cast: function that casts the value into the right type
                           for example if I expect an integer value, the type is 'int'
        :param required: indicates if the value for the option MUST be provided
        """
        self.type = type_cast
        self.name = name
        self.description = description
        self.required = required

    def to_dict(self) -> Dict[str, Any]:
        return {
            "name": self.name,
            "description": self.description,
            "type": self.type.__name__,
            "required": self.required,
        }

    def __repr__(self) -> str:
        return f"<Option({self.name}, {self.description}, required: {self.required})>"

    def __hash__(self) -> int:
        return hash(self.name)

    def __eq__(self, other: object) -> bool:
        if isinstance(other, str):
            return self.name == other
        if isinstance(other, Option):
            return self.name == other.name
        raise TypeError(f"Cannot compare Option with {other.__class__.__name__}")
